macro_rules! archived_style_bytes {
    ($name:literal) => {{
        include_bytes!(concat!(
            "../../archive/styles_zlib/",
            $name,
            ".cbor.zlib"
        )) as &[u8]
    }};
}

macro_rules! archived_locale_bytes {
    ($name:literal) => {{
        include_bytes!(concat!(
            "../../archive/locales_zlib/",
            $name,
            ".cbor.zlib"
        )) as &[u8]
    }};
}

