fn decode_archive_bytes(reader: &[u8]) -> Result<Vec<u8>, String> {
    let mut decoder = zune_inflate::DeflateDecoder::new(reader);
    decoder
        .decode_zlib()
        .map_err(|err| format!("failed to decompress embedded archive entry: {err}"))
}

fn from_cbor<T: DeserializeOwned>(reader: &[u8]) -> Result<T, String> {
    let bytes = decode_archive_bytes(reader)?;
    ciborium::de::from_reader(bytes.as_slice())
        .map_err(|err| format!("failed to decode embedded archive entry: {err}"))
}

/// CBOR-encoded CSL locales.
pub const LOCALES: &[&[u8]] = &[
    archived_locale_bytes!("de-DE"),
    archived_locale_bytes!("en-GB"),
    archived_locale_bytes!("en-US"),
    archived_locale_bytes!("es-ES"),
    archived_locale_bytes!("fr-FR"),
    archived_locale_bytes!("ja-JP"),
    archived_locale_bytes!("pt-BR"),
    archived_locale_bytes!("zh-CN"),
    archived_locale_bytes!("zh-TW"),
];

/// Get all CSL locales.
pub fn locales() -> Vec<Locale> {
    static LOCALE_CACHE: OnceLock<Vec<Locale>> = OnceLock::new();
    LOCALE_CACHE
        .get_or_init(|| {
            LOCALES
                .iter()
                .map(|bytes| from_cbor::<Locale>(bytes).unwrap())
                .collect()
        })
        .clone()
}
